mapper.insert:
INSERT INTO STOCBACH (
	  GATE_CD
	, BUYER_CD
	, CTRL_CD
	, CTRL_USER_ID
	, SEQ
	, REG_DATE
	, REG_USER_ID
	, MOD_DATE
	, MOD_USER_ID
	, CH_TYPE
	, DEL_FLAG
	, USE_FLAG
)
VALUES (
	  #{ses.gateCd}
	, #{BUYER_CD}
	, #{CTRL_CD}
	, #{CTRL_USER_ID}
	, ((SELECT MAX(SEQ)
			 FROM STOCBACH
			WHERE GATE_CD = #{ses.gateCd}
			  AND BUYER_CD = #{BUYER_CD}
			  AND CTRL_CD = #{CTRL_CD}
			  AND CTRL_USER_ID = #{CTRL_USER_ID}), 0) + 1
	, SYSDATE
	, #{ses.userId}
	, SYSDATE
	, #{ses.userId}
	, #{CH_TYPE}
	, '0'
	, #{USE_FLAG}
)

mapper.update:
